            LearningCheckInQuestion("GyanGo எதில் கவனம் செலுத்த வேண்டும்?", listOf("தெளிவு", "ஆய்வு", "சிக்கல் தீர்ப்பு", "சிந்தனை நீட்டிப்பு")),
            LearningCheckInQuestion("தலைப்பு கடினமானால் என்ன?", listOf("எளிமையாக்கு", "பொருந்தும் உதாரணம்", "தர்க்கத்தைப் பிரி", "சவாலுடன் வழிநடத்து")),
            LearningCheckInQuestion("பெரும்பாலான பதில்களில் எவ்வளவு விவரம்?", listOf("அத்தியாவசியம் மட்டும்", "அத்தியாவசியம் + உதாரணங்கள்", "பயிற்சிக்குப் போதும்", "ஆழமும் நீட்டிப்பும்")),
            LearningCheckInQuestion("உங்களைப் போல எது?", listOf("ஆராய்வாளர்", "சிந்தனையாளர்", "கட்டுநர்", "சவாலுடன் கலவை")),
            LearningCheckInQuestion("முதலில் எந்தத் தலைப்பு?", listOf("பொதுத் தலைப்புகள்", "அறிவியல் / இயற்கை", "கணிதம் / முறைகள்", "குறியீடு / உருவாக்கம்")),
            LearningCheckInQuestion("முடிவில் எது பயனுள்ளது?", listOf("குறுகிய முடிவு", "ஒரு நல்ல உதாரணம்", "அடுத்த பயிற்சி படி", "நீட்டிப்புக் கேள்வி")),
            LearningCheckInQuestion("GyanGoக்கு சிறந்த தொனி எது?", listOf("அமைதியும் எளிமையும்", "ஆர்வமும் நுண்ணறிவும்", "தெளிவும் நடைமுறையும்", "கூர்மையும் சவாலும்")),
        )
    }
}
